/* 伪代码：ADT 接口定义 */

typedef struct {
    volatile uint16_t head;
    volatile uint16_t tail;
    uint8_t buf[RING_SIZE];
} ringbuf_t;

void  ringbuf_init(ringbuf_t *rb);
int   ringbuf_data_available(const ringbuf_t *rb);
int   ringbuf_read(ringbuf_t *rb, uint8_t *out, int count);
int   ringbuf_write(ringbuf_t *rb, const uint8_t *in, int count);
bool  ringbuf_is_full(const ringbuf_t *rb);

/* DMA Rx 完成回调：更新环形缓冲区 head */
#define RING_MASK  (511u)
#define RING_SIZE  (512u)

static volatile uint16_t rx_head = 0;
static volatile uint16_t rx_tail = 0;
static uint8_t rx_buf[RING_SIZE]
    __attribute__((aligned(8)));

void HAL_UART_RxCpltCallback(UART_HandleTypeDef *huart)
{
    if (huart->Instance == USART1) {
        /* 1. 确保 DMA 写入的内存对所有核心可见 */
        __DSB();

        /* 2. M7 核清理 Cache */
#if defined(__CORTEX_M) && (__CORTEX_M == 7U)
        SCB_CleanDCache_by_Addr(
            (void *)rx_buf, RING_SIZE);
#endif

        /* 3. 从 CNDTR 计算已传输字节数 */
        uint32_t remaining =
            DMA2->Stream5->CNDTR;
        uint16_t transferred =
            RING_SIZE - (uint16_t)remaining;

        /* 4. 用增量方式更新 head（避免 CNDTR
           重载瞬间导致 transferred=SIZE） */
        static uint16_t prev_head = 0;
        uint16_t delta =
            (transferred - prev_head)
                & RING_MASK;
        prev_head = transferred;

        /* 5. 溢出检测：delta 超过一半说明丢了 */
        if (delta > (RING_SIZE >> 1)) {
            /* 溢出处理：丢弃旧数据 */
            rx_head = transferred;
            rx_tail = transferred;
        } else {
            rx_head += delta;
        }

        /* 6. 重启 DMA 接收（单次模式） */
        HAL_UART_Receive_DMA(
            huart,
            rx_buf,
            RING_SIZE);
    }
}

/* 快照模式：race-free 读取环形缓冲区 */

static uint8_t ringbuf_read_snapshot(
    ringbuf_t *rb,
    uint8_t *out,
    int max_count)
{
    /* 1. 快照 head 和 tail */
    uint16_t h = rb->head;
    uint16_t t = rb->tail;

    /* 2. 计算可用字节数 */
    uint16_t avail = (h >= t)
        ? (h - t)
        : (RING_SIZE - t + h);

    if (avail == 0) return 0;

    /* 3. 限制读取数量 */
    int count = (avail < (uint16_t)max_count)
        ? avail
        : max_count;

    /* 4. 环形读取（可能跨越缓冲区边界） */
    int first_chunk =
        (int)(RING_SIZE - t) < count
        ? (int)(RING_SIZE - t)
        : count;

    memcpy(out, &rb->buf[t], first_chunk);
    if (count > first_chunk) {
        memcpy(
            out + first_chunk,
            rb->buf,
            count - first_chunk);
    }

    /* 5. 更新 tail（在快照之后，安全） */
    rb->tail = (t + count) & RING_MASK;

    return (uint8_t)count;
}

