/* ========== 改进后：ADT 封装 ========== */
typedef struct {
    volatile uint16_t head;
    volatile uint16_t tail;
    uint8_t buf[RING_SIZE];
} ringbuf_t;

static inline uint16_t ringbuf_advance(
    uint16_t ptr)
{
    return (ptr + 1) & RING_MASK;
}

static inline uint16_t ringbuf_count(
    const ringbuf_t *rb)
{
    uint16_t h = rb->head;
    uint16_t t = rb->tail;
    return (h >= t) ? (h - t)
                    : (RING_SIZE - t + h);
}

static inline bool ringbuf_is_full(
    const ringbuf_t *rb)
{
    return ringbuf_count(rb) >= RING_SIZE;
}

/* ISR 中只更新 head */
void DMA_Callback(void) {
    __DSB();
    rx_head = ringbuf_advance(rx_head);
    if (ringbuf_is_full(&ringbuf_rx)) {
        overflow_flag = true;
        rx_tail = rx_head;  /* 丢弃旧数据 */
    }
}

/* 任务中只调用接口 */
void Task(void) {
    uint8_t tmp;
    int n = ringbuf_read_snapshot(
        &ringbuf_rx, &tmp, 1);
    if (n > 0) parse_byte(tmp);
}
